import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"फंक्शंस | Dotfiles (HI)","titleTemplate":":title","description":"शेल फंक्शंस जो आपके टर्मिनल अनुभव को बेहतर बनाते हैं। API टेस्टिंग, फाइल मैनेजमेंट, सिस्टम ऑपरेशन, और अधिक के लिए यूटिलिटीज।","frontmatter":{"title":"फंक्शंस | Dotfiles","description":"शेल फंक्शंस जो आपके टर्मिनल अनुभव को बेहतर बनाते हैं। API टेस्टिंग, फाइल मैनेजमेंट, सिस्टम ऑपरेशन, और अधिक के लिए यूटिलिटीज।","lang":"hi-IN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"फंक्शंस preview","canonical":"/hi/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"फंक्शंस","pageType":"docs","schemaType":"WebPage","metaTitle":"फंक्शंस - Dotfiles (HI)","permalink":"/hi/functions/","meta":[{"name":"keywords","content":"functions, shell, bash, zsh, dotfiles, productivity, utilities, api, file, system, फंक्शंस"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"शेल फंक्शंस जो आपके टर्मिनल अनुभव को बेहतर बनाते हैं। API टेस्टिंग, फाइल मैनेजमेंट, सिस्टम ऑपरेशन, और अधिक के लिए यूटिलिटीज।"},{"name":"twitter:title","content":"फंक्शंस - Dotfiles"},{"name":"og:title","content":"फंक्शंस - Dotfiles"},{"name":"og:description","content":"शेल फंक्शंस जो आपके टर्मिनल अनुभव को बेहतर बनाते हैं। API टेस्टिंग, फाइल मैनेजमेंट, सिस्टम ऑपरेशन, और अधिक के लिए यूटिलिटीज।"},{"name":"og:image:alt","content":"Dotfiles - आपकी शेल लाइफ के लिए डिज़ाइन किया गया"},{"name":"og:locale","content":"hi_IN"}]},"headers":[],"relativePath":"hi/functions/index.md","filePath":"hi/functions/index.md","lastUpdated":1773010926000}'),i={name:"hi/functions/index.md"};function o(s,t,n,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="फंक्शंस" tabindex="-1">फंक्शंस <a class="header-anchor" href="#फंक्शंस" aria-label="Permalink to &quot;फंक्शंस&quot;">​</a></h1><p>macOS, Linux, और Windows में आपकी उत्पादकता बढ़ाने के लिए शेल यूटिलिटीज।</p><h2 id="खोजें" tabindex="-1">खोजें <a class="header-anchor" href="#खोजें" aria-label="Permalink to &quot;खोजें&quot;">​</a></h2><p>फंक्शंस व्यक्तिगत <code>.sh</code> फाइलों के रूप में परिभाषित हैं। <code>chezmoi apply</code> के दौरान, वे <code>~/.config/shell/functions.sh</code> में एकत्र किए जाते हैं और आपके शेल द्वारा स्रोत किए जाते हैं।</p><h2 id="शुरू-करें" tabindex="-1">शुरू करें <a class="header-anchor" href="#शुरू-करें" aria-label="Permalink to &quot;शुरू करें&quot;">​</a></h2><h3 id="एक-फंक्शन-जोड़ें" tabindex="-1">एक फंक्शन जोड़ें <a class="header-anchor" href="#एक-फंक्शन-जोड़ें" aria-label="Permalink to &quot;एक फंक्शन जोड़ें&quot;">​</a></h3><ol><li>एक नई <code>.sh</code> फाइल बनाएं (उदा., <code>myfunc.sh</code>)</li><li>अपना फंक्शन परिभाषा जोड़ें</li><li>परिवर्तन लागू करें:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="संदर्भ" tabindex="-1">संदर्भ <a class="header-anchor" href="#संदर्भ" aria-label="Permalink to &quot;संदर्भ&quot;">​</a></h2><h3 id="api-टेस्टिंग" tabindex="-1">API टेस्टिंग <a class="header-anchor" href="#api-टेस्टिंग" aria-label="Permalink to &quot;API टेस्टिंग&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">एक या अधिक APIs की हेल्थ जांचें</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">API रिस्पॉन्स टाइम मॉनिटर करें</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">बेसिक लोड टेस्टिंग करें</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">टाइमिंग के साथ HTTP रिक्वेस्ट डीबग करें</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="http-यूटिलिटीज" tabindex="-1">HTTP यूटिलिटीज <a class="header-anchor" href="#http-यूटिलिटीज" aria-label="Permalink to &quot;HTTP यूटिलिटीज&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">HTTP हेडर देखें</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">HTTP स्टेटस कोड जांचें</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">HTTP टाइमिंग मेट्रिक्स मापें</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">वेबसाइट सोर्स कोड देखें</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">किसी पोर्ट का उपयोग करने वाली प्रोसेस खोजें</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="फाइल-मैनेजमेंट" tabindex="-1">फाइल मैनेजमेंट <a class="header-anchor" href="#फाइल-मैनेजमेंट" aria-label="Permalink to &quot;फाइल मैनेजमेंट&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">टाइमस्टैम्प्ड बैकअप बनाएं</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Base64 एनकोडिंग और डिकोडिंग</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">आर्काइव फॉर्मेट एक्सट्रैक्ट करें</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">फाइल को हेक्स फॉर्मेट में दिखाएं</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">बैच में एक्सटेंशन रीनेम करें</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">फाइल या डायरेक्टरी साइज जांचें</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">ZIP आर्काइव बनाएं</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="फाइल-नेमिंग" tabindex="-1">फाइल नेमिंग <a class="header-anchor" href="#फाइल-नेमिंग" aria-label="Permalink to &quot;फाइल नेमिंग&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">kebab-case में कन्वर्ट करें</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">lowercase में कन्वर्ट करें</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">sentence case में कन्वर्ट करें</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">snake_case में कन्वर्ट करें</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Title Case में कन्वर्ट करें</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">UPPERCASE में कन्वर्ट करें</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="सिस्टम-यूटिलिटीज" tabindex="-1">सिस्टम यूटिलिटीज <a class="header-anchor" href="#सिस्टम-यूटिलिटीज" aria-label="Permalink to &quot;सिस्टम यूटिलिटीज&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">सिस्टम को स्लीप होने से रोकें</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">OS एनवायरनमेंट पता लगाएं</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">पर्जेबल डिस्क स्पेस साफ करें</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Finder में छिपी फाइलें टॉगल करें</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">होस्ट जानकारी दिखाएं</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">कमांड उपयोग स्टैट्स देखें</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">हाल में संशोधित फाइलें सूचीबद्ध करें</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">क्रॉस-प्लेटफॉर्म लॉगआउट</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">यूजर प्रोसेस सूचीबद्ध करें</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">टर्मिनल स्टॉपवॉच</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">सिस्टम जानकारी दिखाएं</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="caffeine-कमांड्स" tabindex="-1">Caffeine कमांड्स <a class="header-anchor" href="#caffeine-कमांड्स" aria-label="Permalink to &quot;Caffeine कमांड्स&quot;">​</a></h3><p>अपने सिस्टम को स्लीप होने या स्क्रीनसेवर एक्टिवेट होने से रोकें।</p><table tabindex="0"><thead><tr><th style="text-align:left;">कमांड</th><th style="text-align:left;">विवरण</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">caffeine daemon शुरू करें</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">जांचें कि daemon चल रहा है</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">स्क्रीन जागृत रखें</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">स्क्रीन को स्लीप होने दें</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">स्क्रीन जागृत टॉगल करें</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">daemon बंद करें</td></tr></tbody></table><p>macOS (नेटिव <code>caffeinate</code>), Linux (<code>xdg-screensaver</code>), और Windows (PowerShell) पर काम करता है।</p><h3 id="सुरक्षा" tabindex="-1">सुरक्षा <a class="header-anchor" href="#सुरक्षा" aria-label="Permalink to &quot;सुरक्षा&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">मजबूत पासवर्ड जनरेट करें</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">SSH कुंजी जोड़े जनरेट करें</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="नेविगेशन" tabindex="-1">नेविगेशन <a class="header-anchor" href="#नेविगेशन" aria-label="Permalink to &quot;नेविगेशन&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">डायरेक्टरी बदलें और सूची दिखाएं</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">त्वरित डायरेक्टरी नेविगेशन</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">रीड-ओनली को रीड-राइट के रूप में माउंट करें</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">डायरेक्टरी हटाएं</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">सुरक्षित रूप से डिस्क इजेक्ट करें</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="विविध" tabindex="-1">विविध <a class="header-anchor" href="#विविध" aria-label="Permalink to &quot;विविध&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">फंक्शन</th><th style="text-align:left;">विवरण</th><th style="text-align:left;">उपयोग</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">टर्मिनल Matrix इफेक्ट्स</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">PATH में डायरेक्टरी जोड़ें</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">macOS Quick Look में खोलें</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">VS Code में खोलें</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="संगतता" tabindex="-1">संगतता <a class="header-anchor" href="#संगतता" aria-label="Permalink to &quot;संगतता&quot;">​</a></h2><ul><li><strong>macOS</strong> — macOS-विशिष्ट यूटिलिटीज के साथ पूर्ण समर्थन</li><li><strong>Linux</strong> — सामान्य डिस्ट्रीब्यूशन के साथ संगत</li><li><strong>Windows</strong> — WSL, Cygwin, या Git Bash के माध्यम से समर्थन</li></ul><h2 id="सहायता" tabindex="-1">सहायता <a class="header-anchor" href="#सहायता" aria-label="Permalink to &quot;सहायता&quot;">​</a></h2><p>प्रत्येक फंक्शन में <code>--help</code> के माध्यम से डॉक्यूमेंटेशन शामिल है:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",o]]);export{g as __pageData,y as default};
